db:insert.db:input-parameters:
#[{
  ItemId: vars.sfRow.ItemId,
  LocationId: vars.sfRow.LocationId,
  RegionalStock: vars.sfRow.RegionalStock,
  LastUpdatedAt: vars.sfRow.LastUpdatedAt
}]

jms:message.jms:body:
#[{
  itemId: vars.sfRow.ItemId,
  stockLevel: ((vars.sfRow.TotalInventory default 0) as Number),
  timestamp: now() as String
}]

set-variable.value:
#[do {
    var db = (vars.dbRow default [])[0] default {}
    var onhand = (db.onhand default 0) as Number
    var reserved = (db.reserved default 0) as Number
    var regional = (payload.RegionalStock default 0) as Number
    var warehouse = onhand - reserved
    ---
    {
      ItemId: payload.ItemId,
      LocationId: payload.LocationId,
      WarehouseStock: warehouse,
      RegionalStock: regional,
      TotalInventory: warehouse + regional,
      LastUpdatedAt: payload.LastUpdatedAt
    }
  }]

logger.message:
#[%dw 2.0
output application/json
---
{
    ItemId: vars.sfRow.ItemId default payload.ItemId default "N/A", LocationId: vars.sfRow.LocationId default payload.LocationId default "N/A", ErrorType: error.errorType.asString default "No Error", ErrorMessage: error.description default "Unknown Error", PayloadType: payload.^class, sfRow: vars.sfRow default null, dbRow: vars.dbRow default null
}]
